/*
 * compost_monitor.ino — Smart Compost Monitor (ESP32)
 *
 * Elements:
 *   1. DS18B20 1-Wire (3 probes, GPIO 4)  — temperature at 3 depths
 *   2. Capacitive Soil Moisture (GPIO 36)  — compost moisture %
 *   3. SCD41 NDIR CO₂ (I²C 0x62)         — headspace CO₂ + T + RH
 *   4. SSD1306 OLED (I²C 0x3C)            — local live display
 *   5. ESP32 WiFi + MQTT                  — 2-min publish cycle
 *   6. MQTT Alert Logger                  — out-of-range event alerts
 */

#include <Wire.h>
#include <WiFi.h>
#include <PubSubClient.h>
#include <Adafruit_SSD1306.h>
#include <OneWire.h>
#include <DallasTemperature.h>
#include <SensirionI2cScd4x.h>

// --- Credentials ---
const char* SSID      = "HomeNet";
const char* WIFI_PASS = "changeme";
const char* MQTT_HOST = "192.168.1.10";
const int   MQTT_PORT = 1883;

// --- Pins ---
#define DS18B20_PIN  4
#define MOISTURE_PIN 36   // ADC1

// --- Calibration ---
#define MOISTURE_DRY_RAW 3200
#define MOISTURE_WET_RAW  800

// --- Alert thresholds ---
#define TEMP_LOW_ALERT  40.0f
#define MOIST_LOW_ALERT 40.0f
#define CO2_HIGH_ALERT  3000

// --- Publish interval ---
#define PUB_INTERVAL_MS (2UL * 60 * 1000)

// --- Objects ---
OneWire          ow(DS18B20_PIN);
DallasTemperature probes(&ow);
SensirionI2cScd4x scd41;
Adafruit_SSD1306  oled(128, 64, &Wire, -1);
WiFiClient        wifiClient;
PubSubClient      mqtt(wifiClient);

// --- Sensor data ---
float  temps[3]      = {0, 0, 0};
float  moisture_pct  = 0.0f;
uint16_t co2_ppm     = 0;
float  scd_temp      = 0.0f;
float  scd_rh        = 0.0f;

void mqtt_reconnect() {
  while (!mqtt.connected()) {
    if (mqtt.connect("CompostMonitor")) break;
    delay(5000);
  }
}

float read_moisture() {
  long sum = 0;
  for (int i = 0; i < 32; i++) { sum += analogRead(MOISTURE_PIN); delayMicroseconds(100); }
  int raw = sum / 32;
  return constrain(map(raw, MOISTURE_DRY_RAW, MOISTURE_WET_RAW, 0, 100), 0, 100);
}

void update_oled() {
  const char* status = (temps[0] > 45.0f) ? "ACTIVE" :
                        (temps[0] > 35.0f) ? "COOLING" : "DONE/IDLE";
  oled.clearDisplay();
  oled.setTextSize(1); oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0,  0); oled.printf("T: %.1f/%.1f/%.1f", temps[0], temps[1], temps[2]);
  oled.setCursor(0, 12); oled.printf("Moisture: %.0f %%", moisture_pct);
  oled.setCursor(0, 24); oled.printf("CO2: %u ppm", co2_ppm);
  oled.setCursor(0, 36); oled.print(status);
  oled.display();
}

void setup() {
  Serial.begin(115200);
  Wire.begin();

  probes.begin();
  probes.setResolution(12);
  scd41.begin(Wire, 0x62);
  scd41.startPeriodicMeasurement();

  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);
  oled.clearDisplay(); oled.display();

  WiFi.begin(SSID, WIFI_PASS);
  while (WiFi.status() != WL_CONNECTED) delay(500);
  mqtt.setServer(MQTT_HOST, MQTT_PORT);
  mqtt_reconnect();

  Serial.println(F("Compost monitor ready."));
}

void loop() {
  static unsigned long last_pub   = 0;
  static unsigned long last_oled  = 0;
  static unsigned long last_alert = 0;

  unsigned long now = millis();

  if (!mqtt.connected()) mqtt_reconnect();
  mqtt.loop();

  // --- 1. Read SCD41 ---
  uint16_t raw_co2; float raw_t, raw_rh;
  if (scd41.readMeasurement(raw_co2, raw_t, raw_rh) == 0) {
    co2_ppm = raw_co2; scd_temp = raw_t; scd_rh = raw_rh;
  }

  // --- 2. OLED at 2 Hz ---
  if (now - last_oled >= 500UL) {
    last_oled = now;
    probes.requestTemperatures();
    for (int i = 0; i < 3; i++) temps[i] = probes.getTempCByIndex(i);
    moisture_pct = read_moisture();
    update_oled();
  }

  // --- 3. MQTT publish every 2 min ---
  if (now - last_pub >= PUB_INTERVAL_MS) {
    last_pub = now;
    char buf[256];
    snprintf(buf, sizeof(buf),
      "{\"t1\":%.1f,\"t2\":%.1f,\"t3\":%.1f,\"moisture\":%.0f,\"co2\":%u}",
      temps[0], temps[1], temps[2], moisture_pct, co2_ppm);
    mqtt.publish("compost/readings", buf, true);

    // Alerts
    if (now - last_alert >= 3600000UL) {
      bool alert = false;
      char alert_buf[128];
      if (temps[0] < TEMP_LOW_ALERT && temps[0] > 20.0f) {
        snprintf(alert_buf, sizeof(alert_buf), "{\"alert\":\"TEMP_LOW\",\"value\":%.1f}", temps[0]);
        alert = true;
      } else if (moisture_pct < MOIST_LOW_ALERT) {
        snprintf(alert_buf, sizeof(alert_buf), "{\"alert\":\"MOISTURE_LOW\",\"value\":%.0f}", moisture_pct);
        alert = true;
      } else if (co2_ppm > CO2_HIGH_ALERT) {
        snprintf(alert_buf, sizeof(alert_buf), "{\"alert\":\"CO2_HIGH\",\"value\":%u}", co2_ppm);
        alert = true;
      }
      if (alert) { mqtt.publish("compost/alerts", alert_buf); last_alert = now; }
    }
  }

  delay(100);
}
